import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import toast from 'react-hot-toast';
import { ShieldCheck, Terminal, Lock, Activity, Cpu } from 'lucide-react';

const LoginPage = () => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const { login, loading } = useAuth();
  const navigate = useNavigate();

  const handleLogin = async (e) => {
    e.preventDefault();
    
    // System notification for the handshake process
    const toastId = toast.loading("INITIALIZING_SECURE_HANDSHAKE...");
    
    try {
      // login handles the FastAPI OAuth2 form-data conversion internally
      await login(email, password);
      toast.success("IDENTITY_VERIFIED: ACCESS_GRANTED", { id: toastId });
      navigate('/dashboard');
    } catch (err) {
      toast.error(`GATE_ERROR: ${err.message?.toUpperCase() || 'INVALID_CREDENTIALS'}`, { id: toastId });
    }
  };

  return (
    <div className="min-h-[75vh] flex items-center justify-center p-4 reveal-data">
      {/* Central Terminal Card */}
      <div className="w-full max-w-md terminal-card relative overflow-hidden shadow-2xl">
        
        {/* Emerald Laser Scan: Visual security indicator */}
        <div className="absolute top-0 left-0 w-full h-[2px] bg-emerald-500/40 shadow-[0_0_15px_rgba(16,185,129,0.5)] animate-scan" />

        <div className="flex flex-col items-center mb-10">
          <div className="p-4 bg-emerald-500/10 rounded-2xl border border-emerald-500/20 mb-4 text-emerald-500">
            <Cpu size={32} className="animate-pulse" />
          </div>
          <h2 className="text-2xl font-bold tracking-[0.4em] text-white uppercase">Access_Gate</h2>
          <p className="text-[9px] text-white/20 mt-2 uppercase tracking-widest font-mono">
            Node_ID: 8000 // Finify AI Security Protocol
          </p>
        </div>

        <form onSubmit={handleLogin} className="space-y-6">
          {/* Identity Field */}
          <div className="space-y-2">
            <label className="text-[10px] text-emerald-500 font-bold uppercase flex items-center gap-2 mb-1">
              <Terminal size={12} /> Operator_Email
            </label>
            <input 
              type="email"
              disabled={loading}
              className="terminal-input"
              placeholder="operator@finify.ai"
              onChange={(e) => setEmail(e.target.value)}
              required
            />
          </div>

          {/* Security Key Field */}
          <div className="space-y-2">
            <label className="text-[10px] text-emerald-500 font-bold uppercase flex items-center gap-2 mb-1">
              <Lock size={12} /> Secure_Key
            </label>
            <input 
              type="password"
              disabled={loading}
              className="terminal-input"
              placeholder="••••••••"
              onChange={(e) => setPassword(e.target.value)}
              required
            />
          </div>

          {/* Authorization Action */}
          <div className="pt-4">
            <button 
              type="submit" 
              disabled={loading}
              className={`w-full emerald-btn py-4 flex items-center justify-center gap-2 transition-all
                ${loading ? 'opacity-50 cursor-not-allowed' : 'hover:scale-[1.02]'}`}
            >
              {loading ? (
                <>
                  <Activity size={16} className="animate-spin" />
                  <span>SYNCHRONIZING...</span>
                </>
              ) : (
                <>
                  <ShieldCheck size={16} />
                  <span>Connect_to_Terminal</span>
                </>
              )}
            </button>
          </div>
        </form>

        {/* Node Registration Link */}
        <div className="mt-8 pt-6 border-t border-white/5 text-center">
          <p className="text-[10px] text-white/30 uppercase tracking-widest">
            Unauthorized node? 
            <Link to="/register" className="ml-2 text-emerald-500 underline hover:text-emerald-400 transition-colors">
              Initialize_New_Identity
            </Link>
          </p>
        </div>
      </div>
    </div>
  );
};

export default LoginPage;
